using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            return new SchoolContext(options);
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var context = Create(dbName);

            // Seed a department
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = new DateTime(2007, 9, 1)
            };
            context.Departments.Add(department);

            // Seed an instructor
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2000, 1, 15)
            };
            context.Instructors.Add(instructor);

            // Seed a student
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            context.Students.Add(student);

            // Seed a course
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            context.Courses.Add(course);

            // Seed an enrollment
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);

            // Seed office assignment
            var officeAssignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };
            context.OfficeAssignments.Add(officeAssignment);

            // Seed course assignment
            var courseAssignment = new CourseAssignment
            {
                CourseID = 1050,
                InstructorID = 1
            };
            context.CourseAssignments.Add(courseAssignment);

            context.SaveChanges();
            return context;
        }
    }
}

