namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);

            // Assert
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_SetsTotalPages_SinglePage()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 10);

            // Assert
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void Constructor_SetsTotalPages_MultiplePages()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 30, 1, 10);

            // Assert
            Assert.Equal(3, list.TotalPages);
        }

        [Theory]
        [InlineData(11, 10, 2)]
        [InlineData(15, 10, 2)]
        [InlineData(20, 10, 2)]
        [InlineData(21, 10, 3)]
        [InlineData(1, 10, 1)]
        [InlineData(0, 10, 0)]
        public void Constructor_SetsTotalPages_RoundsUpCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 3, 1, 10);

            // Assert
            Assert.Equal(3, list.Count);
            Assert.Equal("a", list[0]);
            Assert.Equal("b", list[1]);
            Assert.Equal("c", list[2]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
