        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 100, pageIndex, 5);

            // Assert
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
