            // Assert
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            // Arrange - 10 items, page size 5, page index 1 (not last page)
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            // Assert
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            // Arrange - 3 items, page size 10, page index 1
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 10);

            // Assert
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectItemsForFirstPage()
        {
            // Arrange
