using System;
using Xunit;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _sut;

        public NotificationServiceTests()
        {
            _sut = new NotificationService();
            // Drain the static queue to ensure test isolation
            while (_sut.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain any remaining notifications
            while (_sut.ReceiveNotification() != null) { }
            _sut.Dispose();
        }

        [Fact]
        public void SendNotification_ThenReceive_ReturnsNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("Student", result.EntityType);
            Assert.Equal("1", result.EntityId);
            Assert.Equal("CREATE", result.Operation);
            Assert.Equal("TestUser", result.CreatedBy);
            Assert.False(result.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Create()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("New Course 'Chemistry' has been created", result.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Update()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("Course 'Chemistry' has been updated", result.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage_Delete()
        {
            // Act
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE, "Admin");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("Course 'Chemistry' has been deleted", result.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("New Student (ID: 42) has been created", result.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("System", result.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "JohnDoe");
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.Equal("JohnDoe", result.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.Null(result);
        }

        [Fact]
        public void SendAndReceive_FIFO_Order()
        {
            // Arrange
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.Equal("Student", first.EntityType);
            Assert.Equal("1", first.EntityId);

            var second = _sut.ReceiveNotification();
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("2", second.EntityId);

            var third = _sut.ReceiveNotification();
            Assert.Equal("Department", third.EntityType);
            Assert.Equal("3", third.EntityId);

            var fourth = _sut.ReceiveNotification();
            Assert.Null(fourth);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.True(result.CreatedAt >= before && result.CreatedAt <= after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.NotNull(result);
            Assert.False(result.IsRead);
