using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using Xunit;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / FullName Tests

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            // Arrange
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            // Act
            var fullName = student.FullName;

            // Assert
            Assert.Equal("Smith, John", fullName);
        }

        [Fact]
        public void Person_FullName_WithMiddleName_ReturnsCorrectFormat()
        {
            // Arrange
            var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane Marie" };

            // Act
            var fullName = instructor.FullName;

            // Assert
            Assert.Equal("Doe, Jane Marie", fullName);
        }

        [Theory]
        [InlineData("Alexander", "Carson", "Alexander, Carson")]
        [InlineData("O'Brien", "Conan", "O'Brien, Conan")]
        [InlineData("Van Der Berg", "Anna", "Van Der Berg, Anna")]
        public void Person_FullName_VariousNames(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Assert
            Assert.Equal(expected, student.FullName);
        }

        #endregion

        #region Student Tests

        [Fact]
        public void Student_Properties_CanBeSetAndRetrieved()
        {
            // Arrange
            var date = new DateTime(2020, 9, 1);
            var student = new Student
            {
                ID = 1,
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = date
            };

            // Assert
            Assert.Equal(1, student.ID);
            Assert.Equal("TestLast", student.LastName);
            Assert.Equal("TestFirst", student.FirstMidName);
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeSet()
        {
            // Arrange
            var student = new Student
            {
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { EnrollmentID = 1, CourseID = 100 },
                    new Enrollment { EnrollmentID = 2, CourseID = 200 }
                }
            };

            // Assert
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_Validation_RequiresLastName()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Now
            };

            // Act
            var results = ValidateModel(student);

            // Assert
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_RequiresFirstMidName()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                EnrollmentDate = DateTime.Now
            };

            // Act
            var results = ValidateModel(student);

            // Assert
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_Validation_LastNameMaxLength50()
        {
            // Arrange
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Now
            };

            // Act
            var results = ValidateModel(student);

            // Assert
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_ValidModel_NoErrors()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "First",
                EnrollmentDate = new DateTime(2020, 1, 1)
            };

            // Act
            var results = ValidateModel(student);

            // Assert
            Assert.Empty(results);
        }

        #endregion

        #region Instructor Tests

        [Fact]
        public void Instructor_Properties_CanBeSetAndRetrieved()
        {
            // Arrange
            var date = new DateTime(2000, 3, 15);
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "InstructorLast",
                FirstMidName = "InstructorFirst",
                HireDate = date
            };

            // Assert
            Assert.Equal(5, instructor.ID);
            Assert.Equal("InstructorLast", instructor.LastName);
            Assert.Equal("InstructorFirst", instructor.FirstMidName);
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void Instructor_CourseAssignments_CanBeSet()
        {
            // Arrange
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1, InstructorID = 1 },
                    new CourseAssignment { CourseID = 2, InstructorID = 1 }
                }
            };

            // Assert
            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void Instructor_OfficeAssignment_CanBeSet()
        {
            // Arrange
            var instructor = new Instructor
            {
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };

            // Assert
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        #endregion

        #region Course Tests

        [Fact]
        public void Course_Properties_CanBeSetAndRetrieved()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            // Assert
            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_Validation_TitleMinLength3()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            // Act
            var results = ValidateModel(course);

            // Assert
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Validation_CreditsRange0to5()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1,
                Title = "ValidTitle",
                Credits = 6,
                DepartmentID = 1
            };

            // Act
            var results = ValidateModel(course);

            // Assert
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Theory]
        [InlineData(0)]
        [InlineData(1)]
        [InlineData(3)]
        [InlineData(5)]
        public void Course_Validation_ValidCredits_NoError(int credits)
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1,
                Title = "ValidTitle",
                Credits = credits,
                DepartmentID = 1
            };

            // Act
            var results = ValidateModel(course);

            // Assert
            Assert.DoesNotContain(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_NavigationProperties_CanBeSet()
        {
            // Arrange
            var course = new Course
            {
                Department = new Department { Name = "Math" },
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Assert
            Assert.NotNull(course.Department);
            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
        }

        #endregion

        #region Department Tests

        [Fact]
        public void Department_Properties_CanBeSetAndRetrieved()
        {
            // Arrange
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5,
                RowVersion = new byte[] { 0x01, 0x02 }
            };

            // Assert
            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(new DateTime(2007, 9, 1), dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
            Assert.Equal(new byte[] { 0x01, 0x02 }, dept.RowVersion);
        }

        [Fact]
        public void Department_InstructorID_Nullable()
        {
            // Arrange
            var dept = new Department { InstructorID = null };

            // Assert
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_Validation_NameMinLength3()
        {
            // Arrange
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Now
            };

