            // Assert
            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_ExistingStudents_DoesNotSeedAgain()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Add one student to simulate existing data
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Now
            });
            context.SaveChanges();

            // Act
            DbInitializer.Initialize(context);

            // Assert - should still be just 1 student (seeding was skipped)
            Assert.Equal(1, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectStudentData()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert - verify specific student data
            var carson = context.Students.FirstOrDefault(s => s.LastName == "Alexander");
            Assert.NotNull(carson);
            Assert.Equal("Carson", carson.FirstMidName);
            Assert.Equal(new DateTime(2010, 9, 1), carson.EnrollmentDate);
        }

        [Fact]
        public void Initialize_SeedsCorrectInstructorData()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var kim = context.Instructors.FirstOrDefault(i => i.LastName == "Abercrombie");
            Assert.NotNull(kim);
            Assert.Equal("Kim", kim.FirstMidName);
            Assert.Equal(new DateTime(1995, 3, 11), kim.HireDate);
        }

