            // Assert
            var english = context.Departments.FirstOrDefault(d => d.Name == "English");
            Assert.NotNull(english);
            Assert.Equal(350000m, english.Budget);
        }

        [Fact]
        public void Initialize_SeedsCorrectCourseData()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            var chemistry = context.Courses.FirstOrDefault(c => c.CourseID == 1050);
            Assert.NotNull(chemistry);
            Assert.Equal("Chemistry", chemistry.Title);
            Assert.Equal(3, chemistry.Credits);
        }

        [Fact]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert - verify enrollments have grades
            var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).Count();
            var enrollmentsWithoutGrades = context.Enrollments.Where(e => e.Grade == null).Count();
            Assert.True(enrollmentsWithGrades > 0);
            Assert.True(enrollmentsWithoutGrades > 0);
        }

        [Fact]
        public void Initialize_CalledTwice_DoesNotDuplicateData()
        {
