using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        private SchoolContext CreateContext()
        {
            return TestDbContextFactory.Create(Guid.NewGuid().ToString());
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            // Arrange
            using var context = CreateContext();
            var controller = new HomeController(context);

            // Act
            var result = controller.Index();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = TestDbContextFactory.Create(dbName);

            // Seed students with different enrollment dates
            context.Students.Add(new Student { FirstMidName = "A", LastName = "Test1", EnrollmentDate = new DateTime(2020, 9, 1) });
            context.Students.Add(new Student { FirstMidName = "B", LastName = "Test2", EnrollmentDate = new DateTime(2020, 9, 1) });
            context.Students.Add(new Student { FirstMidName = "C", LastName = "Test3", EnrollmentDate = new DateTime(2021, 9, 1) });
            context.SaveChanges();

            var controller = new HomeController(context);

            // Act
            var result = controller.About() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);

            var group2020 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
            Assert.NotNull(group2020);
            Assert.Equal(2, group2020.StudentCount);

            var group2021 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2021, 9, 1));
            Assert.NotNull(group2021);
            Assert.Equal(1, group2021.StudentCount);
        }

        [Fact]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            // Arrange
            using var context = CreateContext();
            var controller = new HomeController(context);

            // Act
            var result = controller.About() as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.NotNull(model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            // Arrange
            using var context = CreateContext();
            var controller = new HomeController(context);

            // Act
            var result = controller.Contact() as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            // Arrange
            using var context = CreateContext();
            var controller = new HomeController(context);

            // Act
            var result = controller.Error();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            // Arrange
            using var context = CreateContext();
            var controller = new HomeController(context);

            // Act
            var result = controller.Unauthorized() as ViewResult;

            // Assert
            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

