using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateSeededContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var context = TestDbContextFactory.Create(dbName);

            var students = new[]
            {
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2019, 9, 1) },
                new Student { ID = 3, LastName = "Baker", FirstMidName = "David", EnrollmentDate = new DateTime(2021, 1, 15) },
                new Student { ID = 4, LastName = "Chen", FirstMidName = "Li", EnrollmentDate = new DateTime(2018, 9, 1) },
                new Student { ID = 5, LastName = "Davis", FirstMidName = "Mark", EnrollmentDate = new DateTime(2020, 1, 15) }
            };

            context.Students.AddRange(students);
            context.SaveChanges();
            return context;
        }

        private StudentsController CreateControllerWithTempData(SchoolContext context)
        {
            var controller = new StudentsController(context);
            var httpContext = new DefaultHttpContext();
            var tempDataProvider = new Mock<ITempDataProvider>();
            controller.TempData = new TempDataDictionary(httpContext, tempDataProvider.Object);
            controller.ControllerContext = new ControllerContext { HttpContext = httpContext };
            return controller;
        }

        #region Index Tests

        [Fact]
        public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(5, model.Count);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Baker", model[2].LastName);
            Assert.Equal("Chen", model[3].LastName);
            Assert.Equal("Davis", model[4].LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal("Davis", model[0].LastName);
            Assert.Equal("Chen", model[1].LastName);
            Assert.Equal("Baker", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            // Earliest date first
            Assert.Equal("Chen", model[0].LastName); // 2018
            Assert.Equal("Alonso", model[1].LastName); // 2019
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            // Latest date first
            Assert.Equal("Baker", model[0].LastName); // 2021-01-15
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index(null, null, "Al", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count); // Alexander and Alonso
            Assert.All(model, s => Assert.Contains("Al", s.LastName));
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            var result = controller.Index(null, null, "Carson", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_NewSearch_ResetsPageTo1()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act - new search string provided (not null)
            var result = controller.Index(null, null, "Baker", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_CurrentFilter_PreservesSearch()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act - no new search string, use currentFilter
            var result = controller.Index(null, "Baker", null, 1) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Baker", model[0].LastName);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            controller.Index(null, null, null, null);

            // Assert
            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
            Assert.Equal("Date", controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsCorrectViewBagParms()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            // Act
            controller.Index("name_desc", null, null, null);

            // Assert
            Assert.Equal("", controller.ViewBag.NameSortParm); // toggles back to ascending
        }

        [Fact]
        public void Index_Pagination_RespectsPageSize()
        {
            // Arrange
