using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateSeededContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var context = TestDbContextFactory.Create(dbName);

            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = DateTime.Now };
            context.Departments.Add(dept);

            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2000, 1, 15),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Adams",
                FirstMidName = "Jane",
                HireDate = new DateTime(2005, 6, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.AddRange(instructor1, instructor2);

            var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var course2 = new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 };
            context.Courses.AddRange(course1, course2);

            context.CourseAssignments.Add(new CourseAssignment { CourseID = 1050, InstructorID = 1 });
            context.CourseAssignments.Add(new CourseAssignment { CourseID = 2021, InstructorID = 1 });

            context.SaveChanges();
            return context;
        }

        #region Index Tests

        [Fact]
        public void Index_NoParams_ReturnsViewWithAllInstructors()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Index(null, null) as ViewResult;

            // Assert
            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Index(null, null) as ViewResult;

            // Assert
            var model = result.Model as InstructorIndexData;
            var instructorList = model.Instructors.ToList();
            Assert.Equal("Adams", instructorList[0].LastName);
            Assert.Equal("Smith", instructorList[1].LastName);
        }

        [Fact]
        public void Index_WithInstructorId_SetsCourses()
        {
            // Arrange
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            // Act
            var result = controller.Index(1, null) as ViewResult;

            // Assert
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count());
        }

