using System;
using System.Collections.Generic;
using Xunit;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly NotificationService _drainHelper;

        public NotificationsControllerTests()
        {
            _drainHelper = new NotificationService();
            // Drain static queue for test isolation
            while (_drainHelper.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            while (_drainHelper.ReceiveNotification() != null) { }
            _drainHelper.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.Index();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            Assert.NotNull(value);

            // Check the dynamic response
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsList()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Enqueue notifications via the service
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
            service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE, "Admin");

            // Act
            var result = controller.GetNotifications();

            // Assert
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(2, (int)countProp.GetValue(value));

            var notificationsProp = value.GetType().GetProperty("notifications");
            var notifications = notificationsProp.GetValue(value) as List<Notification>;
            Assert.NotNull(notifications);
            Assert.Equal(2, notifications.Count);
            Assert.Equal("Student", notifications[0].EntityType);
            Assert.Equal("Course", notifications[1].EntityType);

            service.Dispose();
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Enqueue more than 10 notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(value));

            service.Dispose();
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.MarkAsRead(1);

            // Assert
            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_DifferentIds_ReturnsSuccess()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Act & Assert - various IDs all succeed
            var result1 = controller.MarkAsRead(0);
            var result2 = controller.MarkAsRead(999);
            var result3 = controller.MarkAsRead(-1);

            Assert.All(new[] { result1, result2, result3 }, r =>
            {
                var val = r.Value;
                var prop = val.GetType().GetProperty("success");
                Assert.True((bool)prop.GetValue(val));
            });
        }

        [Fact]
        public void GetNotifications_AfterReceiving_QueueIsDrained()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var service = new NotificationService();
            service.SendNotification("Test", "1", EntityOperation.CREATE);

            // Act - first call gets the notification
            controller.GetNotifications();

            // Second call should be empty
            var result = controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(value));

            service.Dispose();
        }
    }
}

